#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int T = 1;
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        long long arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &arr[i]);
        }
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            sum += arr[i];
        }
        long long dp[N + 1][sum + N * K + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= sum + N * K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= sum + N * K; j++) {
                if (j - arr[i - 1] >= 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - arr[i - 1]]) % MOD;
                }
                if (j - arr[i - 1] - K >= 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - arr[i - 1] - K]) % MOD;
                }
            }
        }
        long long ans = 0;
        for (int i = 0; i <= sum + N * K; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

