            for (int i = 0; i < N; i++) {
                sum += arr[i];
            }
            long[][] dp = new long[N + 1][(int) (sum + N * K + 1)];
            dp[0][0] = 1;
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= sum + N * K; j++) {
                    if (j - arr[i - 1] >= 0) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - (int) arr[i - 1]]) % 1000000007;
                    }
                    if (j - arr[i - 1] - K >= 0) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - (int) arr[i - 1] - K]) % 1000000007;
                    }
                }
            }
            long ans = 0;
            for (int i = 0; i <= sum + N * K; i++) {
                ans = (ans + dp[N][i]) % 1000000007;
